
using Masofa.Common.Models.Dictionaries;
using Masofa.Common.Models.SystemCrical;
using Masofa.DataAccess;
using Microsoft.EntityFrameworkCore;
using NetTopologySuite.Geometries;

namespace Masofa.Cli.DevopsUtil.Commands.DataCompare
{
    [BaseCommand("Region And RegionMap Compare", "Загрузка данных по погоде по датам")]
    public class RegionAndRegionMapCompareCommad : IBaseCommand
    {
        public RegionAndRegionMapCompareCommad(MasofaCropMonitoringDbContext masofaCropMonitoringDbContext, MasofaDictionariesDbContext masofaDictionariesDbContext)
        {
            MasofaCropMonitoringDbContext = masofaCropMonitoringDbContext;
            MasofaDictionariesDbContext = masofaDictionariesDbContext;
        }

        private MasofaCropMonitoringDbContext MasofaCropMonitoringDbContext { get; }
        private MasofaDictionariesDbContext MasofaDictionariesDbContext { get; }

        public async Task Execute()
        {
            var regions = MasofaDictionariesDbContext.Regions.AsNoTracking().ToList();
            var regionMaps = MasofaDictionariesDbContext.RegionMaps.AsNoTracking().ToList();
            var count = 0;
            var result = new List<Region>();
            Console.OutputEncoding = System.Text.Encoding.UTF8;
            foreach (var region in regions)
            {
                if (!regionMaps.Any(rm => rm.Id == region.RegionMapId))
                {
                    count++;
                    result.Add(region);
                    Console.WriteLine($"Region map for region {region.Names["ru-RU"]} with id {region.Id} - not exist");
                }
            }

            Console.WriteLine($"Region without RegionMap is {count}");
            var tempJson = File.ReadAllText("C:\\Users\\k-kal\\Documents\\6grain\\Stash\\Masofa\\uz_selected.geojson");
            var newRegionsMap = Newtonsoft.Json.JsonConvert.DeserializeObject<FeatureCollection>(tempJson);
            foreach (var item in newRegionsMap.Features)
            {
                var tempRegion = regions.FirstOrDefault(m => m.Names["ru-RU"] == item.Properties.target_ru);
                if (tempRegion == null)
                {
                    continue;
                }
                var tempRM = regionMaps.FirstOrDefault(rm => rm.Id == tempRegion.RegionMapId);
                if ((tempRM != null) && (!string.IsNullOrEmpty(tempRM.PolygonJson)))
                {
                    continue;
                }
                var tempPolygonJson = new ClearGeometry()
                {
                    type = "Polygon"
                };
                if (item.Geometry.Type == "Polygon")
                {
                    tempPolygonJson.coordinates = item.Geometry.Coordinates;
                }
                else
                {
                    tempPolygonJson.coordinates = new List<List<List<double>>>();
                    foreach (var mp in item.Geometry.Multicoordinates)
                    {
                        tempPolygonJson.coordinates.AddRange(mp);
                    }
                }
                var  imageOutlineCoordinates = new List<Coordinate>();
                foreach (var image in tempPolygonJson.coordinates[0])
                {
                    imageOutlineCoordinates.Add(new Coordinate(image[0], image[1]));
                }
                GeometryFactory geometryFactory = new GeometryFactory();
                Polygon poly = geometryFactory.CreatePolygon(imageOutlineCoordinates.ToArray());
                var tempRegionMap = new RegionMap()
                {
                    CreateAt = DateTime.UtcNow,
                    LastUpdateAt = DateTime.UtcNow,
                    CreateUser = Guid.Parse("01993e2c-0880-716b-9f41-27686a6a5e0a"),
                    LastUpdateUser = Guid.Parse("01993e2c-0880-716b-9f41-27686a6a5e0a"),
                    Status = Common.Models.StatusType.Active,
                    Polygon = poly.Factory.CreateMultiPolygon([poly]),
                    Lat = (decimal)poly.Centroid.Y,
                    Lng = (decimal)poly.Centroid.X,
                    MozaikX = 1,
                    MozaikY = 1
                };
                tempRegionMap = MasofaDictionariesDbContext.RegionMaps.Add(tempRegionMap).Entity;
                tempRegion.RegionMapId = tempRegionMap.Id;
                MasofaDictionariesDbContext.Regions.Update(tempRegion);
                MasofaDictionariesDbContext.SaveChanges();
            }

        }

        public void Dispose()
        {
            throw new NotImplementedException();
        }

        public Task Execute(string[] args)
        {
            throw new NotImplementedException();
        }

