    public class FeatureCollection
    {
        public string Type { get; set; } = "FeatureCollection";
        public Crs Crs { get; set; }
        public List<Feature> Features { get; set; }
    }

    public class Crs
    {
        public string Type { get; set; }
        public CrsProperties Properties { get; set; }
    }

    public class CrsProperties
    {
        public string Name { get; set; }
    }

    public class Feature
    {
        public string Type { get; set; } = "Feature";
        public FeatureProperties Properties { get; set; }
        public Geometry Geometry { get; set; }
    }

    public class FeatureProperties
    {
        public string target_ru { get; set; } // "target_ru"
        public string matched_name { get; set; } // "matched_name"
        public string matched_col { get; set; } // "matched_col"
        public double match_score { get; set; } // "match_score"
    }

    public class Geometry
    {
        public string Type { get; set; } // "Polygon" или "MultiPolygon"
        public List<List<List<double>>> Coordinates { get; set; } 
        public List<List<List<List<double>>>> Multicoordinates { get; set; }
    }

    public class ClearGeometry
    {
        public string type { get; set; } // "Polygon" или "MultiPolygon"
        public List<List<List<double>>> coordinates { get; set; }
    }
}
